The circuit breaker pattern prevents cascading failures when a downstream service is unavailable, by fast-failing calls and providing fallback behavior.

**States:**
- **CLOSED:** Normal operation; requests pass through
- **OPEN:** Service is failing; fast-fail all requests
- **HALF_OPEN:** Testing recovery; allow one probe request

```java
import java.util.concurrent.atomic.*;
import java.util.concurrent.locks.ReentrantLock;
import java.time.Instant;

public class CircuitBreaker {
    public enum State { CLOSED, OPEN, HALF_OPEN }

    private final int failureThreshold;       // failures before opening
    private final long resetTimeoutMs;        // how long to stay OPEN
    private final int successThreshold;       // successes to close from HALF_OPEN

    private volatile State state = State.CLOSED;
    private final AtomicInteger failureCount = new AtomicInteger(0);
    private final AtomicInteger successCount = new AtomicInteger(0);
    private volatile long openedAt = 0;
    private final ReentrantLock stateLock = new ReentrantLock();

    public CircuitBreaker(int failureThreshold, long resetTimeoutMs, int successThreshold) {
        this.failureThreshold = failureThreshold;
        this.resetTimeoutMs = resetTimeoutMs;
        this.successThreshold = successThreshold;
    }

    public <T> T execute(CheckedSupplier<T> action, CheckedSupplier<T> fallback) throws Exception {
        if (!allowRequest()) {
            System.out.println("Circuit OPEN — using fallback");
            return fallback.get();
        }
        try {
            T result = action.get();
            onSuccess();
            return result;
        } catch (Exception e) {
            onFailure();
            return fallback.get();
        }
    }

    private boolean allowRequest() {
        if (state == State.CLOSED) return true;
        if (state == State.OPEN) {
            if (System.currentTimeMillis() - openedAt >= resetTimeoutMs) {
                transitionTo(State.HALF_OPEN);
                return true; // probe request
            }
            return false;
        }
        return state == State.HALF_OPEN; // one probe at a time
    }

    private void onSuccess() {
        if (state == State.HALF_OPEN) {
            if (successCount.incrementAndGet() >= successThreshold) {
                failureCount.set(0);
                successCount.set(0);
                transitionTo(State.CLOSED);
            }
        } else {
            failureCount.set(0); // reset on success
        }
    }

    private void onFailure() {
        if (state == State.HALF_OPEN) {
            transitionTo(State.OPEN); // probe failed — re-open
        } else if (failureCount.incrementAndGet() >= failureThreshold) {
            transitionTo(State.OPEN);
        }
    }

    private void transitionTo(State newState) {
        stateLock.lock();
        try {
            state = newState;
            if (newState == State.OPEN) {
                openedAt = System.currentTimeMillis();
                System.out.println("Circuit OPENED at " + Instant.now());
            } else if (newState == State.CLOSED) {
                System.out.println("Circuit CLOSED at " + Instant.now());
            }
        } finally {
            stateLock.unlock();
        }
    }

    @FunctionalInterface
    interface CheckedSupplier<T> { T get() throws Exception; }
}
```

